package dev.yazidcv.cv;
import dev.yazidcv.common.AuditedEntity; import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="cv_documents") public class CvDocument extends AuditedEntity{
 @Column(name="organization_id") private UUID organizationId; @Column(name="candidate_id") private UUID candidateId; @Column(name="original_filename") private String originalFilename; @Column(name="storage_key") private String storageKey; @Column(name="content_type") private String contentType; @Column(name="file_size") private long fileSize; private String checksum; private String status; @Column(name="uploaded_by") private String uploadedBy; @Column(name="extracted_text",columnDefinition="text") private String extractedText; @Column(name="extraction_method") private String extractionMethod; @Column(name="processing_error") private String processingError; @Column(name="completed_at") private Instant completedAt;
 protected CvDocument(){} public CvDocument(UUID org,UUID candidate,String filename,String key,String type,long size,String checksum,String actor){organizationId=org;candidateId=candidate;originalFilename=filename;storageKey=key;contentType=type;fileSize=size;this.checksum=checksum;uploadedBy=actor;status="UPLOADED";}
 public void processing(){status="PARSING";processingError=null;} public void completed(UUID candidate,String text){candidateId=candidate;extractedText=text;extractionMethod="APACHE_TIKA";status="COMPLETED";completedAt=Instant.now();} public void ocrRequired(String message){status="OCR_REQUIRED";processingError=message;extractionMethod="OCR_REQUIRED";} public void failed(String message){status="FAILED";processingError=message;}
 public UUID getOrganizationId(){return organizationId;} public UUID getCandidateId(){return candidateId;} public String getOriginalFilename(){return originalFilename;} public String getStorageKey(){return storageKey;} public String getContentType(){return contentType;} public long getFileSize(){return fileSize;} public String getStatus(){return status;} public String getExtractionMethod(){return extractionMethod;} public String getProcessingError(){return processingError;} public Instant getCompletedAt(){return completedAt;} public String getExtractedText(){return extractedText;}
}
